     1→<script lang="ts">
     2→	import type { Container } from '$lib/types/container.js';
     3→	import StatusPill from './StatusPill.svelte';
     4→
     5→	export let container: Container;
     6→
     7→	type Tab = 'overview' | 'devcontainer' | 'env' | 'ports';
     8→	let activeTab: Tab = 'overview';
     9→
    10→	// Env editing state
    11→	let newEnvKey = '';
    12→	let newEnvValue = '';
    13→	let envError = '';
    14→
    15→	// Local copy of env vars for editing
    16→	let envVars: Record<string, string> = { ...(container.config.env ?? {}) };
    17→
    18→	// Start/stop/action state
    19→	let actionLoading = false;
    20→	let actionError = '';
    21→
    22→	async function handleStart(): Promise<void> {
    23→		actionLoading = true;
    24→		actionError = '';
    25→		try {
    26→			const res = await fetch(`/api/containers/${container.id}/start`, { method: 'POST' });
    27→			if (!res.ok) {
    28→				const body = await res.json();
    29→				actionError = body.error ?? 'Failed to start container';
    30→			} else {
    31→				const updated: Container = await res.json();
    32→				container = updated;
    33→			}
    34→		} catch {
    35→			actionError = 'Network error';
    36→		} finally {
    37→			actionLoading = false;
    38→		}
    39→	}
    40→
    41→	async function handleStop(): Promise<void> {
    42→		actionLoading = true;
    43→		actionError = '';
    44→		try {
    45→			const res = await fetch(`/api/containers/${container.id}/stop`, { method: 'POST' });
    46→			if (!res.ok) {
    47→				const body = await res.json();
    48→				actionError = body.error ?? 'Failed to stop container';
    49→			} else {
    50→				const updated: Container = await res.json();
    51→				container = updated;
    52→			}
    53→		} catch {
    54→			actionError = 'Network error';
    55→		} finally {
    56→			actionLoading = false;
    57→		}
    58→	}
    59→
    60→	function addEnvVar(): void {
    61→		const key = newEnvKey.trim();
    62→		const value = newEnvValue.trim();
    63→		if (!key) {
    64→			envError = 'Key is required';
    65→			return;
    66→		}
    67→		envError = '';
    68→		envVars = { ...envVars, [key]: value };
    69→		newEnvKey = '';
    70→		newEnvValue = '';
    71→	}
    72→
    73→	function removeEnvVar(key: string): void {
    74→		const updated = { ...envVars };
    75→		delete updated[key];
    76→		envVars = updated;
    77→	}
    78→
    79→	$: devcontainerJson = JSON.stringify(
    80→		{
    81→			image: container.config.image,
    82→			containerEnv: container.config.env,
    83→			forwardPorts: container.config.ports,
    84→			mounts: container.config.mounts,
    85→			customizations: container.config.extensions?.length
    86→				? { vscode: { extensions: container.config.extensions } }
    87→				: undefined,
    88→			postCreateCommand: container.config.postCreateCommand
    89→		},
    90→		null,
    91→		2
    92→	);
    93→
    94→	$: ports = container.config.ports ?? [];
    95→	$: repoUrl = container.config.repoUrl ?? null;
    96→</script>
